// frontend/src/components/ParticleCanvas.jsx
import { useRef, useEffect } from "react";
import * as THREE from "three";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls";
import { CSS2DRenderer, CSS2DObject } from "three/examples/jsm/renderers/CSS2DRenderer";
import { createSun, createPlanets } from "../utils/solarSystem";

export default function ParticleCanvas({ userid, stage, status, startSimulation, pauseSimulation, changeStage }) {
  const mountRef = useRef();
  const changeStageRef = useRef(changeStage);

  useEffect(() => {
    changeStageRef.current = changeStage;
  }, [changeStage]);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const width = mount.clientWidth;
    const height = mount.clientHeight;

    // --- Scene & Camera ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x000000);

    const camera = new THREE.PerspectiveCamera(60, width / height, 1, 50000);
    camera.position.set(0, 2500, 10000);

    // --- Renderer ---
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(width, height);
    mount.appendChild(renderer.domElement);

    // --- CSS2DRenderer for Labels ---
    const labelRenderer = new CSS2DRenderer();
    labelRenderer.setSize(width, height);
    labelRenderer.domElement.style.position = "absolute";
    labelRenderer.domElement.style.top = "0";
    mount.appendChild(labelRenderer.domElement);

    // --- Controls ---
    const controls = new OrbitControls(camera, labelRenderer.domElement);
    controls.enableDamping = true;
    controls.enablePan = false;

    // --- Lights ---
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.35);
    scene.add(ambientLight);
    const sunLight = new THREE.PointLight(0xffffff, 2.2, 0, 2);
    sunLight.position.set(0, 0, 0);
    sunLight.userData.isStageObject = true;
    scene.add(sunLight);

    let stageObject = null;
    let sun = null;
    let planets = [];

    // --- Big Bang Animation State ---
    let bigBangStartTime = null;
    let isBigBangAnimating = false;
    const BIGBANG_DURATION = 5000; // 5 seconds

    const setupStage = () => {
      scene.children.filter((obj) => obj.userData.isStageObject).forEach((obj) => scene.remove(obj));
      stageObject = null;
      sun = null;
      planets = [];

      // --- Solar System ---
      if (stage === "solar_system") {
        sun = createSun(CSS2DObject);
        sun.userData.isStageObject = true;
        scene.add(sun);

        planets = createPlanets(scene, CSS2DObject);
        planets.forEach((p) => { p.mesh.userData.isStageObject = true; });

        camera.position.set(0, 500, 2500);
        controls.target.set(0, 0, 0);
        controls.update();
      }

      // --- BigBang ---
      if (stage === "bigbang") {
        const geometry = new THREE.BufferGeometry();
        const numParticles = 800000;
        const positions = new Float32Array(numParticles * 3);
        const initialPositions = new Float32Array(numParticles * 3);
        const colors = new Float32Array(numParticles * 3);
        const color = new THREE.Color();

        // Start with particles very close to origin (pre-Big Bang high density state)
        for (let i = 0; i < numParticles; i++) {
          const r = Math.random() * 50; // 매우 작은 반지름으로 시작 (고밀도)
          const theta = Math.random() * Math.PI * 2;
          const phi = Math.random() * Math.PI;
          initialPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
          initialPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
          initialPositions[i * 3 + 2] = r * Math.cos(phi);

          // 흰색으로 설정
          color.setRGB(1, 1, 1);
          colors[i * 3] = color.r;
          colors[i * 3 + 1] = color.g;
          colors[i * 3 + 2] = color.b;

          // 초기 위치 저장
          positions[i * 3] = initialPositions[i * 3];
          positions[i * 3 + 1] = initialPositions[i * 3 + 1];
          positions[i * 3 + 2] = initialPositions[i * 3 + 2];
        }

        geometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
        geometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));

        stageObject = new THREE.Points(
          geometry,
          new THREE.PointsMaterial({ size: 3, vertexColors: true, sizeAttenuation: true })
        );
        stageObject.userData.isStageObject = true;
        stageObject.userData.initialPositions = initialPositions;
        stageObject.userData.geometry = geometry;
        scene.add(stageObject);

        // Start Big Bang animation
        bigBangStartTime = Date.now();
        isBigBangAnimating = true;

        camera.position.set(0, 0, 2000);
        controls.target.set(0, 0, 0);
        controls.update();
      }

      // --- Galaxy Formation ---
      if (stage === "galaxy_formation") {
        const group = new THREE.Group();
        const numParticles = 600000;
        const geometry = new THREE.BufferGeometry();
        const positions = new Float32Array(numParticles * 3);
        const colors = new Float32Array(numParticles * 3);
        const sizes = new Float32Array(numParticles);
        const color = new THREE.Color();

        // 실제 별의 색상 스펙트럼 (온도에 따른 색상)
        const starColors = [
          { r: 0.6, g: 0.7, b: 1.0 },    // 파란색 (고온)
          { r: 0.8, g: 0.85, b: 1.0 },   // 청백색
          { r: 1.0, g: 1.0, b: 1.0 },    // 흰색
          { r: 1.0, g: 0.95, b: 0.8 },   // 노란색
          { r: 1.0, g: 0.85, b: 0.6 },   // 주황색
          { r: 1.0, g: 0.7, b: 0.5 },    // 빨간색 (저온)
        ];

        for (let i = 0; i < numParticles; i++) {
          // 나선은하 구조 생성 (로그 나선)
          const spiralArms = 2;
          const armIndex = Math.floor(Math.random() * spiralArms);
          const baseAngle = (armIndex / spiralArms) * Math.PI * 2;

          // 거리 분포 (중심부에 더 많은 별)
          const rBase = Math.random();
          const r = Math.pow(rBase, 0.5) * 6000;

          // 로그 나선 각도 계산
          const spiralTightness = 0.3;
          const theta = baseAngle + Math.log(r / 100 + 1) * spiralTightness + (Math.random() - 0.5) * 0.4;

          // 나선팔의 두께 (거리가 멀수록 더 넓게)
          const armThickness = (0.1 + Math.random() * 0.15) * (1 + r / 4000);
          const radialOffset = (Math.random() - 0.5) * armThickness;
          const finalR = Math.max(0, r + radialOffset);

          // Y축 압축 (은하 원반 구조)
          const yCompression = 0.12 + Math.random() * 0.08;
          const yOffset = (Math.random() - 0.5) * 200 * yCompression;

          positions[i * 3] = finalR * Math.cos(theta);
          positions[i * 3 + 1] = yOffset;
          positions[i * 3 + 2] = finalR * Math.sin(theta);

          // 거리에 따른 색상 선택
          // 중심부: 더 밝고 파란 별들, 외곽: 노란색/빨간색
          let colorIndex;
          const normalizedR = r / 6000;
          if (normalizedR < 0.3) {
            // 중심부 - 밝고 파란 별들
            colorIndex = Math.floor(Math.random() * 3); // 파란색, 청백색, 흰색
          } else if (normalizedR < 0.7) {
            // 중간부 - 흰색, 노란색
            colorIndex = 2 + Math.floor(Math.random() * 2); // 흰색, 노란색
          } else {
            // 외곽부 - 노란색, 주황색, 빨간색
            colorIndex = 3 + Math.floor(Math.random() * 3); // 노란색, 주황색, 빨간색
          }

          const starColor = starColors[colorIndex];
          const brightness = 0.7 + Math.random() * 0.3; // 밝기 변화
          color.setRGB(
            starColor.r * brightness,
            starColor.g * brightness,
            starColor.b * brightness
          );

          colors[i * 3] = color.r;
          colors[i * 3 + 1] = color.g;
          colors[i * 3 + 2] = color.b;

          // 크기도 다양하게 - 중심부의 별이 더 크고 밝음
          const baseSize = 1.5 + Math.random() * 1.5;
          sizes[i] = baseSize * (1 + (1 - normalizedR) * 0.5);
        }

        geometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
        geometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));
        geometry.setAttribute("size", new THREE.BufferAttribute(sizes, 1));

        // 별들을 위한 쉐이더 머티리얼
        const stars = new THREE.Points(
          geometry,
          new THREE.PointsMaterial({
            size: 2.5,
            vertexColors: true,
            blending: THREE.AdditiveBlending,
            transparent: true,
            opacity: 1.0,
            sizeAttenuation: true,
            depthWrite: false,
          })
        );
        group.add(stars);

        // 중심부에 밝은 별 클러스터 추가
        const centerGeometry = new THREE.BufferGeometry();
        const centerParticles = 50000;
        const centerPositions = new Float32Array(centerParticles * 3);
        const centerColors = new Float32Array(centerParticles * 3);
        const centerSizes = new Float32Array(centerParticles);

        for (let i = 0; i < centerParticles; i++) {
          const r = Math.random() * 800; // 중심부만
          const theta = Math.random() * Math.PI * 2;
          const phi = Math.random() * Math.PI;

          centerPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
          centerPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta) * 0.2;
          centerPositions[i * 3 + 2] = r * Math.cos(phi);

          // 중심부는 더 밝고 파란색
          const brightness = 0.9 + Math.random() * 0.1;
          color.setRGB(0.7 * brightness, 0.8 * brightness, 1.0 * brightness);
          centerColors[i * 3] = color.r;
          centerColors[i * 3 + 1] = color.g;
          centerColors[i * 3 + 2] = color.b;

          centerSizes[i] = 2 + Math.random() * 2;
        }

        centerGeometry.setAttribute("position", new THREE.BufferAttribute(centerPositions, 3));
        centerGeometry.setAttribute("color", new THREE.BufferAttribute(centerColors, 3));
        centerGeometry.setAttribute("size", new THREE.BufferAttribute(centerSizes, 1));

        const centerStars = new THREE.Points(
          centerGeometry,
          new THREE.PointsMaterial({
            size: 3,
            vertexColors: true,
            blending: THREE.AdditiveBlending,
            transparent: true,
            opacity: 1.0,
            sizeAttenuation: true,
            depthWrite: false,
          })
        );
        group.add(centerStars);

        group.userData.isStageObject = true;
        stageObject = group;
        scene.add(stageObject);

        camera.position.set(0, 200, 1500);
        controls.target.set(0, 0, 0);
        controls.update();
      }
    };

    setupStage();

    let frameId;
    const animate = () => {
      // 카메라 거리에 따라 파티클 크기 조정 (축소 시 채워지게)
      const cameraDistance = camera.position.distanceTo(controls.target);

      if (stage === "solar_system" && sun) {
        sun.rotation.y += 0.002;
        planets.forEach((p) => {
          p.angle += p.speed;
          p.mesh.position.x = p.radius * Math.cos(p.angle);
          p.mesh.position.z = p.radius * Math.sin(p.angle);
        });
      } else if (stage === "bigbang" && stageObject && isBigBangAnimating) {
        // Big Bang explosion animation
        const elapsed = Date.now() - bigBangStartTime;
        const progress = Math.min(elapsed / BIGBANG_DURATION, 1);

        // Exponential expansion (matches cosmology inflation model)
        const expansionFactor = Math.pow(progress * 60 + 1, 2); // 1 ~ 3721

        const positions = stageObject.geometry.attributes.position.array;
        const initialPositions = stageObject.userData.initialPositions;

        for (let i = 0; i < positions.length; i += 3) {
          positions[i] = initialPositions[i] * expansionFactor;
          positions[i + 1] = initialPositions[i + 1] * expansionFactor;
          positions[i + 2] = initialPositions[i + 2] * expansionFactor;
        }

        stageObject.geometry.attributes.position.needsUpdate = true;

        // Also add slow rotation for visual effect
        stageObject.rotation.y += 0.0005;

        // 카메라 거리에 따라 파티클 크기 조정 (축소 시 채워지게)
        const baseSize = 3;
        const distanceFactor = Math.max(1, cameraDistance / 2000);
        stageObject.material.size = baseSize * distanceFactor;

        // When animation completes, transition to galaxy_formation
        if (progress >= 1) {
          isBigBangAnimating = false;
          // Small delay before transition
          setTimeout(() => {
            changeStageRef.current("galaxy_formation");
          }, 500);
        }
      } else if (stage === "bigbang" && stageObject && !isBigBangAnimating) {
        // Big Bang 완료 후에도 파티클 크기 조정
        const baseSize = 3;
        const distanceFactor = Math.max(1, cameraDistance / 2000);
        stageObject.material.size = baseSize * distanceFactor;
        stageObject.rotation.y += 0.0005;
      } else if (stage === "galaxy_formation" && stageObject) {
        // 은하 회전
        stageObject.rotation.y += 0.0003;

        // 카메라 거리에 따라 파티클 크기 조정 (축소 시 채워지게)
        const baseSize = 2.5;
        const distanceFactor = Math.max(1, cameraDistance / 1500);
        stageObject.children.forEach((child) => {
          if (child.material) {
            child.material.size = baseSize * distanceFactor;
          }
        });
      }

      controls.update();
      renderer.render(scene, camera);
      labelRenderer.render(scene, camera);

      frameId = requestAnimationFrame(animate);
    };
    animate();

    const onResize = () => {
      const newWidth = mount.clientWidth;
      const newHeight = mount.clientHeight;
      camera.aspect = newWidth / newHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(newWidth, newHeight);
      labelRenderer.setSize(newWidth, newHeight);
    };
    window.addEventListener("resize", onResize);

    return () => {
      cancelAnimationFrame(frameId);
      window.removeEventListener("resize", onResize);
      renderer.dispose();
      mount.removeChild(renderer.domElement);
      mount.removeChild(labelRenderer.domElement);
    };
  }, [stage]);

  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100vw", height: "100vh" }}>
      <div ref={mountRef} style={{ width: "100%", height: "100%" }} />

      <div style={{ position: "absolute", top: 10, left: 10, zIndex: 100, display: "flex", gap: "8px" }}>
        <button onClick={startSimulation}>Start</button>
        <button onClick={pauseSimulation}>{status === "paused" ? "Resume" : "Pause"}</button>
        <button onClick={() => changeStage("bigbang")}>BigBang</button>
        <button onClick={() => changeStage("galaxy_formation")}>Galaxy</button>
        <button onClick={() => changeStage("solar_system")}>SolarSystem</button>
      </div>
    </div>
  );
}
